BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?value ?name WHERE {
  VALUES ?target {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Use%2520Cases>
  }
  ?target vocab:NamedElement_name ?name .
  ?target ?prop ?value .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?type ?name WHERE {
  <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::09%20Views::TMT-APS-SE::TMT-APS%20Use%20Cases>
    vocab:Element_ownedElement ?child .
  ?child rdf:type ?type .
  OPTIONAL { ?child vocab:NamedElement_name ?name . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?type ?name WHERE {
  VALUES ?pkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Use%2520Cases>
  }
  ?pkg vocab:Element_ownedElement ?child .
  ?child rdf:type ?type .
  OPTIONAL { ?child vocab:NamedElement_name ?name . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?useCase ?name WHERE {
  VALUES ?pkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Use%2520Cases>
  }

  ?pkg vocab:Element_ownedElement+ ?useCase .
  ?useCase rdf:type vocab:usecase .
  ?useCase vocab:NamedElement_name ?name .

  FILTER NOT EXISTS {
    ?container vocab:Element_ownedElement+ ?useCase .
    ?container rdf:type vocab:usecase .
  }
}
ORDER BY ?name
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?type ?name (COUNT(*) as ?cnt) WHERE {
  VALUES ?pkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Use%2520Cases>
  }
  ?pkg vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }
}
GROUP BY ?type ?name
ORDER BY DESC(?cnt)
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?qname ?name WHERE {
  VALUES ?pkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE::TMT-APS%2520Use%2520Cases>
  }
  ?pkg vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qname . }
}
ORDER BY ?type
LIMIT 25
